#[cfg(test)]
mod tests {
    use super::*;
    use backbone_core::state_machine::StateMachineBehavior;

    #[test]
    fn test_initial_state() {
        let sm = SessionStateMachine::default();
        assert_eq!(sm.current_state(), SessionState::Active);
        assert!(sm.current_state().is_initial());
    }

    #[test]
    fn test_valid_transition() {
        let mut sm = SessionStateMachine { current_state: SessionState::Active };
        assert!(sm.can_transition(SessionTransition::Revoke));
        let result = sm.transition(SessionTransition::Revoke);
        assert!(result.is_ok());
        assert_eq!(sm.current_state(), SessionState::Revoked);
    }

    #[test]
    fn test_invalid_transition() {
        let mut sm = SessionStateMachine { current_state: SessionState::Revoked };
        // Revoke is not valid from Revoked state
        let result = sm.transition(SessionTransition::Revoke);
        assert!(result.is_err());
    }

    #[test]
    fn test_state_parsing() {
        let state: SessionState = "active".parse().unwrap();
        assert_eq!(state, SessionState::Active);
    }

    #[test]
    fn test_available_transitions() {
        let sm = SessionStateMachine::default();
        let available = sm.available_transitions();
        // Should have at least some transitions available from initial state
        assert!(!available.is_empty() || sm.current_state().is_final());
    }
}
